#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return (*y)[1] - (*x)[1];
}

int main() {
    int T, N, Bi, Li;
    long long maxSweetness = 0;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int songs[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &Bi, &Li);
            songs[i][0] = Bi;
            songs[i][1] = Li;
        }
        qsort(songs, N, sizeof(int) * 2, compare);
        int bands[N] = {0};
        maxSweetness = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < i; j++) {
                if (songs[j][0] != songs[i][0]) {
                    bands[i]++;
                }
            }
            long long sweetness = (long long)songs[i][1] * (bands[i] + 1);
            maxSweetness += sweetness;
        }
        printf("%lld\n", maxSweetness);
    }
    return 0;
}

