import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[][] songs = new int[N][2];
            for (int i = 0; i < N; i++) {
                songs[i][0] = scanner.nextInt();
                songs[i][1] = scanner.nextInt();
            }
            Arrays.sort(songs, (a, b) -> b[1] - a[1]);
            int[] bands = new int[N];
            long maxSweetness = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < i; j++) {
                    if (songs[j][0] != songs[i][0]) {
                        bands[i]++;
                    }
                }
                long sweetness = (long)songs[i][1] * (bands[i] + 1);
                maxSweetness += sweetness;
            }
            System.out.println(maxSweetness);
        }
    }
}

