const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
let T = parseInt(lines[i++]);
while (T-- > 0) {
    let N = parseInt(lines[i++]);
    let songs = [];
    for (let j = 0; j < N; j++) {
        let [Bi, Li] = lines[i++].split(' ').map(num => parseInt(num));
        songs.push([Bi, Li]);
    }
    songs.sort((a, b) => b[1] - a[1]);
    let bands = new Array(N).fill(0);
    let maxSweetness = 0;
    for (let j = 0; j < N; j++) {
        for (let k = 0; k < j; k++) {
            if (songs[k][0] !== songs[j][0]) {
                bands[j]++;
            }
        }
        let sweetness = songs[j][1] * (bands[j] + 1);
        maxSweetness += sweetness;
    }
    console.log(maxSweetness);
}
